"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[6846],{6846:e=>{e.exports=JSON.parse('{"28":{"words":[{"spanish":"Si tuviera m\xe1s tiempo","english":"If I had more time"},{"spanish":"Si fuera posible","english":"If it were possible"},{"spanish":"Si pudiera elegir","english":"If I could choose"},{"spanish":"Si supiera la respuesta","english":"If I knew the answer"},{"spanish":"Si viniera conmigo","english":"If he or she came with me"},{"spanish":"Si pusieras m\xe1s atenci\xf3n","english":"If you paid more attention"},{"spanish":"Si dijeran la verdad","english":"If they told the truth"},{"spanish":"Si hubiera menos ruido","english":"If there were less noise"},{"spanish":"Me hablaron como si fuera experta","english":"They spoke to me as if I were an expert"},{"spanish":"Ojal\xe1 pudiera descansar","english":"I wish I could rest"},{"spanish":"Ojal\xe1 no lloviera ma\xf1ana","english":"I wish it would not rain tomorrow"},{"spanish":"Aunque fuera dif\xedcil","english":"Even if it were difficult"},{"spanish":"Si me ofrecieran el puesto","english":"If they offered me the job"},{"spanish":"Si no estuviera tan cansado","english":"If I were not so tired"},{"spanish":"Si nos mud\xe1ramos","english":"If we moved"},{"spanish":"Si saliera m\xe1s temprano","english":"If I left earlier"},{"spanish":"Si hicieras ejercicio","english":"If you exercised"},{"spanish":"Si tuviera sentido","english":"If it made sense"},{"spanish":"La situaci\xf3n hipot\xe9tica","english":"The hypothetical situation"},{"spanish":"El deseo poco probable","english":"The unlikely wish"},{"spanish":"La beca internacional","english":"The international scholarship"},{"spanish":"El cambio radical","english":"The radical change"},{"spanish":"La segunda oportunidad","english":"The second chance"},{"spanish":"El arrepentimiento","english":"The regret"},{"spanish":"La decisi\xf3n arriesgada","english":"The risky decision"},{"spanish":"La reacci\xf3n inesperada","english":"The unexpected reaction"},{"spanish":"La versi\xf3n ideal","english":"The ideal version"},{"spanish":"La mudanza so\xf1ada","english":"The dreamed-of move"},{"spanish":"El horario flexible","english":"The flexible schedule"},{"spanish":"La confianza suficiente","english":"Enough confidence"},{"spanish":"El jefe comprensivo","english":"The understanding boss"},{"spanish":"El vecino ruidoso","english":"The noisy neighbor"},{"spanish":"El proyecto solidario","english":"The community support project"},{"spanish":"La inversi\xf3n inicial","english":"The initial investment"},{"spanish":"La meta ambiciosa","english":"The ambitious goal"},{"spanish":"La respuesta sincera","english":"The sincere response"},{"spanish":"La salida de emergencia","english":"The emergency exit"},{"spanish":"La experiencia previa","english":"Previous experience"},{"spanish":"La condici\xf3n necesaria","english":"The necessary condition"},{"spanish":"La comparaci\xf3n exagerada","english":"The exaggerated comparison"},{"spanish":"El consejo contrafactual","english":"The counterfactual advice"},{"spanish":"La posibilidad remota","english":"The remote possibility"}],"conversations":[{"id":1,"topic":"Una beca para estudiar en Lisboa","dialog":[{"speaker":"Paula","spanish":"Si me concedieran la beca de Lisboa, me mudar\xeda en septiembre, pero todav\xeda no s\xe9 si mi expediente ser\xeda suficiente.","english":"If they granted me the Lisbon scholarship, I would move in September, but I still do not know whether my academic record would be enough."},{"speaker":"Andr\xe9s","spanish":"Yo creo que s\xed. Tus profesores hablan de ti como si fueras una investigadora joven con mucha experiencia.","english":"I think so. Your professors speak about you as if you were a young researcher with a great deal of experience."},{"speaker":"Paula","spanish":"Ojal\xe1 pensaran igual en el comit\xe9. Si no tuviera que trabajar tantas horas, preparar\xeda mejor la entrevista.","english":"I wish the committee thought the same. If I did not have to work so many hours, I would prepare better for the interview."},{"speaker":"Andr\xe9s","spanish":"Aunque fuera una entrevista muy exigente, responder\xedas bien. Si yo fuera t\xfa, practicar\xeda en voz alta esta semana.","english":"Even if it were a very demanding interview, you would do well. If I were you, I would practice out loud this week."},{"speaker":"Paula","spanish":"Lo har\xeda encantada. Tambi\xe9n me preocupa el dinero; si el alojamiento fuera demasiado caro, tendr\xeda que compartir piso.","english":"I would gladly do it. I am also worried about the money; if the housing were too expensive, I would have to share an apartment."},{"speaker":"Andr\xe9s","spanish":"Pues si te aceptaran, varios antiguos becarios te dar\xedan consejos y quiz\xe1 hasta te recomendar\xedan una residencia asequible.","english":"Well, if they accepted you, several former scholarship recipients would give you advice and might even recommend an affordable residence hall."}],"questions":[{"question":"\xbfCu\xe1l es la meta principal de Paula?","options":["Mudarse a Chile por trabajo","Conseguir una beca para estudiar en Lisboa","Abrir un negocio con Andr\xe9s","Cambiar de carrera de inmediato"],"answerIndex":1,"answer":"Conseguir una beca para estudiar en Lisboa"},{"question":"\xbfPor qu\xe9 dice Paula que preparar\xeda mejor la entrevista en otras circunstancias?","options":["Porque no tendr\xeda que trabajar tantas horas","Porque hablar\xeda portugu\xe9s con fluidez","Porque ya conocer\xeda la ciudad","Porque tendr\xeda m\xe1s cartas de recomendaci\xf3n"],"answerIndex":0,"answer":"Porque no tendr\xeda que trabajar tantas horas"},{"question":"Si la aceptaran, \xbfqu\xe9 apoyo menciona Andr\xe9s?","options":["Un contrato garantizado en una empresa","Consejos de antiguos becarios y quiz\xe1 una residencia asequible","Un coche para moverse por la ciudad","Clases privadas gratis durante un a\xf1o"],"answerIndex":1,"answer":"Consejos de antiguos becarios y quiz\xe1 una residencia asequible"}]},{"id":2,"topic":"La b\xfasqueda de un piso m\xe1s tranquilo","dialog":[{"speaker":"Rosa","spanish":"Si el vecino de arriba no tocara la bater\xeda a medianoche, dormir\xeda mucho mejor y rendir\xeda m\xe1s en el trabajo.","english":"If the upstairs neighbor did not play the drums at midnight, I would sleep much better and perform better at work."},{"speaker":"Miguel","spanish":"Ya lo s\xe9. Ayer actu\xf3 como si el edificio fuera suyo y nadie m\xe1s necesitara descansar.","english":"I know. Yesterday he acted as if the building were his and nobody else needed to rest."},{"speaker":"Rosa","spanish":"Ojal\xe1 la administradora le pusiera una advertencia formal. Si pudiera mudarme este mes, lo har\xeda sin pensarlo.","english":"I wish the building manager would give him a formal warning. If I could move this month, I would do it without thinking twice."},{"speaker":"Miguel","spanish":"Aunque el alquiler fuera m\xe1s alto en otro barrio, vivir\xedas con mucha m\xe1s tranquilidad.","english":"Even if the rent were higher in another neighborhood, you would live much more peacefully."},{"speaker":"Rosa","spanish":"S\xed, pero si encontrara un piso cercano a la oficina, ahorrar\xeda tiempo y tambi\xe9n dinero en transporte.","english":"Yes, but if I found an apartment near the office, I would save time and also money on transportation."},{"speaker":"Miguel","spanish":"Entonces yo hablar\xeda con una amiga agente inmobiliaria; si surgiera algo razonable, te avisar\xeda hoy mismo.","english":"Then I would speak with a friend who is a real estate agent; if something reasonable came up, I would let you know today."}],"questions":[{"question":"\xbfC\xf3mo afecta el ruido del vecino a Rosa?","options":["La obliga a cambiar de trabajo","Hace que duerma peor y rinda menos","Le impide estudiar portugu\xe9s","La hace llegar tarde al gimnasio"],"answerIndex":1,"answer":"Hace que duerma peor y rinda menos"},{"question":"\xbfQu\xe9 desear\xeda Rosa que hiciera la administradora?","options":["Que organizara una reuni\xf3n de vecinos","Que redujera el alquiler del edificio","Que le pusiera una advertencia formal al vecino","Que cerrara la sala com\xfan"],"answerIndex":2,"answer":"Que le pusiera una advertencia formal al vecino"},{"question":"\xbfQui\xe9n podr\xeda ayudar a Rosa a encontrar otro piso?","options":["Una amiga agente inmobiliaria de Miguel","El vecino de arriba","Un profesor de la universidad","La hermana menor de Rosa"],"answerIndex":0,"answer":"Una amiga agente inmobiliaria de Miguel"}]},{"id":3,"topic":"Un centro de apoyo escolar para el barrio","dialog":[{"speaker":"Elena","spanish":"Si el ayuntamiento nos cediera el local vac\xedo, abrir\xedamos un centro de apoyo escolar para adolescentes del barrio.","english":"If city hall gave us the empty space, we would open an academic support center for teenagers in the neighborhood."},{"speaker":"Diego","spanish":"Ser\xeda incre\xedble. Incluso la gente colaborar\xeda como si el proyecto fuera suyo, porque hace falta un espacio as\xed.","english":"That would be incredible. People would even collaborate as if the project were their own, because a space like that is needed."},{"speaker":"Elena","spanish":"Ojal\xe1 algunos negocios donaran computadoras. Si tuvi\xe9ramos ese material, podr\xedamos ofrecer tutor\xedas y talleres de empleo.","english":"I wish some businesses would donate computers. If we had that equipment, we could offer tutoring and job workshops."},{"speaker":"Diego","spanish":"Aunque fuera dif\xedcil al principio, conseguir\xedamos voluntarios. La clave ser\xeda presentar un plan muy concreto.","english":"Even if it were difficult at first, we would get volunteers. The key would be to present a very concrete plan."},{"speaker":"Elena","spanish":"Tambi\xe9n pienso que, si viniera m\xe1s gente jubilada, los estudiantes recibir\xedan ayuda personalizada y compa\xf1\xeda.","english":"I also think that, if more retired people came, the students would receive personalized help and company."},{"speaker":"Diego","spanish":"Exacto. Si lanz\xe1ramos la campa\xf1a esta semana, llegar\xedamos a septiembre con tiempo para organizarnos bien.","english":"Exactly. If we launched the campaign this week, we would reach September with enough time to organize ourselves well."}],"questions":[{"question":"\xbfQu\xe9 abrir\xedan si el ayuntamiento les cediera el local?","options":["Una tienda de tecnolog\xeda","Un centro de apoyo escolar para adolescentes","Una oficina tur\xedstica","Un restaurante comunitario"],"answerIndex":1,"answer":"Un centro de apoyo escolar para adolescentes"},{"question":"\xbfQu\xe9 tipo de donaci\xf3n espera Elena?","options":["Computadoras para ofrecer tutor\xedas y talleres","Uniformes deportivos para un club","Billetes de tren para los voluntarios","Instrumentos musicales para conciertos"],"answerIndex":0,"answer":"Computadoras para ofrecer tutor\xedas y talleres"},{"question":"\xbfPor qu\xe9 propone Diego lanzar la campa\xf1a esta semana?","options":["Para cerrar el proyecto antes del verano","Para llegar a septiembre con tiempo para organizarse","Para competir con otro barrio","Para evitar hablar con el ayuntamiento"],"answerIndex":1,"answer":"Para llegar a septiembre con tiempo para organizarse"}]},{"id":4,"topic":"La oportunidad de trabajar en otro pa\xeds","dialog":[{"speaker":"Sara","spanish":"Si aceptara el puesto en Chile, cambiar\xeda de vida por completo, pero me asusta dejar a mi familia aqu\xed.","english":"If I accepted the position in Chile, my life would change completely, but I am afraid of leaving my family here."},{"speaker":"Nicol\xe1s","spanish":"Es normal. Sin embargo, hablas del proyecto como si ya supieras que te har\xeda crecer much\xedsimo.","english":"That is normal. Even so, you talk about the project as if you already knew it would help you grow enormously."},{"speaker":"Sara","spanish":"Puede ser. Ojal\xe1 mi madre no se preocupara tanto; si me viera m\xe1s segura, quiz\xe1 me apoyar\xeda m\xe1s.","english":"That may be true. I wish my mother did not worry so much; if she saw me more confident, maybe she would support me more."},{"speaker":"Nicol\xe1s","spanish":"Aunque fuera un cambio enorme, podr\xedas volver despu\xe9s de un a\xf1o con m\xe1s experiencia y contactos.","english":"Even if it were a huge change, you could come back after a year with more experience and contacts."},{"speaker":"Sara","spanish":"S\xed, y si no aprovechara ahora la oportunidad, me arrepentir\xeda durante mucho tiempo.","english":"Yes, and if I did not take advantage of the opportunity now, I would regret it for a long time."},{"speaker":"Nicol\xe1s","spanish":"Entonces haz una lista. Si las ventajas superaran tus miedos, tomar\xedas la decisi\xf3n con m\xe1s claridad.","english":"Then make a list. If the advantages outweighed your fears, you would make the decision more clearly."}],"questions":[{"question":"\xbfQu\xe9 es lo que m\xe1s asusta a Sara sobre el puesto en Chile?","options":["No entender el acento local","Dejar a su familia en su pa\xeds","Perder su pasaporte durante el viaje","No encontrar vivienda amueblada"],"answerIndex":1,"answer":"Dejar a su familia en su pa\xeds"},{"question":"Seg\xfan Nicol\xe1s, \xbfqu\xe9 har\xeda el proyecto por Sara?","options":["La har\xeda crecer much\xedsimo","Le quitar\xeda toda su energ\xeda","La obligar\xeda a cambiar de profesi\xf3n","Le resolver\xeda los problemas familiares"],"answerIndex":0,"answer":"La har\xeda crecer much\xedsimo"},{"question":"\xbfQu\xe9 m\xe9todo le sugiere Nicol\xe1s para decidir?","options":["Preguntar a diez desconocidos","Esperar sin hablar con nadie","Hacer una lista y comparar ventajas con miedos","Aceptar el puesto esa misma noche"],"answerIndex":2,"answer":"Hacer una lista y comparar ventajas con miedos"}]}],"stories":[{"id":1,"title":"Si Marta tuviera un d\xeda extra","sentences":[{"spanish":"Si Marta tuviera un d\xeda libre m\xe1s cada semana, retomar\xeda sus clases de piano y visitar\xeda a su abuela con calma.","english":"If Marta had one more free day each week, she would return to her piano lessons and visit her grandmother without rushing."},{"spanish":"Ahora sale del trabajo tan cansada que a veces cena como si todav\xeda estuviera en la oficina.","english":"Now she leaves work so tired that sometimes she eats dinner as if she were still at the office."},{"spanish":"Ojal\xe1 su jefe le ofreciera un horario m\xe1s flexible durante el verano.","english":"She wishes her boss would offer her a more flexible schedule during the summer."},{"spanish":"Aunque fuera un cambio peque\xf1o, sentir\xeda que recupera una parte importante de su vida.","english":"Even if it were a small change, she would feel that she was getting back an important part of her life."},{"spanish":"Su amiga Paula le dijo que, si aprendiera a delegar algunas tareas, dormir\xeda mejor y se concentrar\xeda m\xe1s.","english":"Her friend Paula told her that if she learned to delegate some tasks, she would sleep better and focus more."},{"spanish":"Marta sabe que no puede cambiarlo todo de inmediato, pero imaginarlo la ayuda a decidir por d\xf3nde empezar.","english":"Marta knows she cannot change everything immediately, but imagining it helps her decide where to start."}]},{"id":2,"title":"Ojal\xe1 no estuviera tan lejos","sentences":[{"spanish":"Desde que su hermano se mud\xf3 a Canad\xe1, Ver\xf3nica habla con \xe9l cada domingo y le pregunta c\xf3mo ser\xeda su vida si vivieran en la misma ciudad.","english":"Ever since her brother moved to Canada, Ver\xf3nica talks with him every Sunday and asks him what life would be like if they lived in the same city."},{"spanish":"\xc9l responde que, si estuviera m\xe1s cerca, cuidar\xeda a los sobrinos algunos fines de semana y compartir\xedan m\xe1s tiempo en familia.","english":"He replies that if he were closer, he would watch the nieces and nephews on some weekends and they would spend more time together as a family."},{"spanish":"Ver\xf3nica lo escucha con nostalgia, porque a veces siente que las videollamadas no bastan.","english":"Ver\xf3nica listens to him with nostalgia because sometimes she feels video calls are not enough."},{"spanish":"Ojal\xe1 pudiera visitarlo este invierno, aunque fuera solo por diez d\xedas.","english":"She wishes she could visit him this winter, even if it were only for ten days."},{"spanish":"Mientras ahorra, mira vuelos y act\xfaa como si la decisi\xf3n dependiera \xfanicamente del calendario.","english":"While she saves up, she looks at flights and acts as if the decision depended only on the calendar."},{"spanish":"Ese peque\xf1o sue\xf1o la anima a seguir organizando sus gastos con paciencia.","english":"That small dream encourages her to keep organizing her expenses patiently."}]},{"id":3,"title":"Aunque fuera arriesgado","sentences":[{"spanish":"El\xedas siempre ha dicho que, si encontrara un local asequible, abrir\xeda una panader\xeda de barrio.","english":"El\xedas has always said that if he found an affordable storefront, he would open a neighborhood bakery."},{"spanish":"Sus amigos lo apoyan y hablan del proyecto como si ya probaran el pan caliente cada ma\xf1ana.","english":"His friends support him and talk about the project as if they were already tasting warm bread every morning."},{"spanish":"Ojal\xe1 un banco peque\xf1o le concediera el pr\xe9stamo inicial que necesita.","english":"He wishes a small bank would grant him the initial loan he needs."},{"spanish":"Aunque fuera arriesgado dejar su empleo actual, \xe9l aceptar\xeda el reto porque conf\xeda en su experiencia.","english":"Even if it were risky to leave his current job, he would take on the challenge because he trusts his experience."},{"spanish":"Si lograra empezar antes de diciembre, aprovechar\xeda la temporada de fiestas para darse a conocer.","english":"If he managed to start before December, he would take advantage of the holiday season to make himself known."},{"spanish":"Por ahora sigue haciendo cuentas y buscando el momento en que la idea deje de ser hipot\xe9tica.","english":"For now he keeps doing the math and looking for the moment when the idea stops being hypothetical."}]}],"speaking":{"title":"Hip\xf3tesis, deseos y situaciones improbables","description":"Practica el imperfecto de subjuntivo con si clauses, deseos poco probables y comparaciones irreales.","questions_and_answers":[{"question":{"spanish":"\xbfQu\xe9 har\xedas si tuvieras un mes libre?","english":"What would you do if you had a free month?"},"answer":{"spanish":"Si tuviera un mes libre, viajar\xeda por el sur de Espa\xf1a.","english":"If I had a free month, I would travel through southern Spain."}},{"question":{"spanish":"\xbfD\xf3nde vivir\xedas si pudieras trabajar desde cualquier lugar?","english":"Where would you live if you could work from anywhere?"},"answer":{"spanish":"Si pudiera trabajar desde cualquier lugar, vivir\xeda cerca del mar.","english":"If I could work from anywhere, I would live near the sea."}},{"question":{"spanish":"\xbfQu\xe9 estudiar\xedas si te concedieran una beca?","english":"What would you study if they granted you a scholarship?"},"answer":{"spanish":"Si me concedieran una beca, estudiar\xeda pol\xedticas p\xfablicas.","english":"If they granted me a scholarship, I would study public policy."}},{"question":{"spanish":"\xbfQu\xe9 comprar\xedas si ganaras un premio grande?","english":"What would you buy if you won a big prize?"},"answer":{"spanish":"Si ganara un premio grande, comprar\xeda un apartamento peque\xf1o para mi madre.","english":"If I won a big prize, I would buy a small apartment for my mother."}},{"question":{"spanish":"\xbfC\xf3mo reaccionar\xedas si un vecino hiciera ruido cada noche?","english":"How would you react if a neighbor made noise every night?"},"answer":{"spanish":"Si un vecino hiciera ruido cada noche, hablar\xeda con la administraci\xf3n.","english":"If a neighbor made noise every night, I would speak with the building management."}},{"question":{"spanish":"\xbfQu\xe9 desear\xedas cambiar de tu rutina?","english":"What would you wish to change about your routine?"},"answer":{"spanish":"Ojal\xe1 tuviera un horario m\xe1s flexible.","english":"I wish I had a more flexible schedule."}},{"question":{"spanish":"\xbfQu\xe9 har\xedas si hablaras cinco idiomas?","english":"What would you do if you spoke five languages?"},"answer":{"spanish":"Si hablara cinco idiomas, trabajar\xeda en proyectos internacionales.","english":"If I spoke five languages, I would work on international projects."}},{"question":{"spanish":"\xbfC\xf3mo te sentir\xedas si tu equipo perdiera el apoyo financiero?","english":"How would you feel if your team lost financial support?"},"answer":{"spanish":"Si mi equipo perdiera el apoyo financiero, buscar\xeda donaciones y aliados nuevos.","english":"If my team lost financial support, I would look for donations and new partners."}},{"question":{"spanish":"\xbfQu\xe9 har\xedas si te ofrecieran trabajo en otro pa\xeds?","english":"What would you do if they offered you a job in another country?"},"answer":{"spanish":"Si me ofrecieran trabajo en otro pa\xeds, lo pensar\xeda con calma y hablar\xeda con mi familia.","english":"If they offered me a job in another country, I would think it over calmly and talk with my family."}},{"question":{"spanish":"\xbfC\xf3mo describir\xedas a alguien muy dram\xe1tico?","english":"How would you describe someone very dramatic?"},"answer":{"spanish":"Habla como si cada problema fuera una cat\xe1strofe.","english":"He or she talks as if every problem were a catastrophe."}},{"question":{"spanish":"\xbfQu\xe9 har\xedas si tuvieras m\xe1s energ\xeda por las ma\xf1anas?","english":"What would you do if you had more energy in the mornings?"},"answer":{"spanish":"Si tuviera m\xe1s energ\xeda por las ma\xf1anas, har\xeda ejercicio antes de trabajar.","english":"If I had more energy in the mornings, I would exercise before work."}},{"question":{"spanish":"\xbfQu\xe9 desear\xedas para tu ciudad?","english":"What would you wish for your city?"},"answer":{"spanish":"Ojal\xe1 hubiera m\xe1s parques y bibliotecas p\xfablicas.","english":"I wish there were more parks and public libraries."}},{"question":{"spanish":"\xbfQu\xe9 har\xedas aunque fuera dif\xedcil?","english":"What would you do even if it were difficult?"},"answer":{"spanish":"Aunque fuera dif\xedcil, terminar\xeda el m\xe1ster.","english":"Even if it were difficult, I would finish the master\u2019s degree."}},{"question":{"spanish":"\xbfC\xf3mo actuar\xedas si supieras que la oportunidad no volver\xeda?","english":"How would you act if you knew the opportunity would not return?"},"answer":{"spanish":"Si supiera que la oportunidad no volver\xeda, aceptar\xeda el riesgo.","english":"If I knew the opportunity would not return, I would accept the risk."}},{"question":{"spanish":"\xbfQu\xe9 pasar\xeda si salieras una hora antes del trabajo?","english":"What would happen if you left work an hour earlier?"},"answer":{"spanish":"Si saliera una hora antes del trabajo, cocinar\xeda con m\xe1s calma.","english":"If I left work an hour earlier, I would cook more calmly."}},{"question":{"spanish":"\xbfQu\xe9 har\xedas si tuvieras un mentor excelente?","english":"What would you do if you had an excellent mentor?"},"answer":{"spanish":"Si tuviera un mentor excelente, aprovechar\xeda cada reuni\xf3n para aprender.","english":"If I had an excellent mentor, I would make the most of every meeting to learn."}},{"question":{"spanish":"\xbfC\xf3mo ayudar\xedas a tu barrio si tuvieras recursos?","english":"How would you help your neighborhood if you had resources?"},"answer":{"spanish":"Si tuviera recursos, abrir\xeda un centro comunitario para j\xf3venes.","english":"If I had resources, I would open a community center for young people."}},{"question":{"spanish":"\xbfQu\xe9 dir\xedas de una persona muy segura de s\xed misma?","english":"What would you say about someone very self-assured?"},"answer":{"spanish":"Habla como si nunca dudara de s\xed misma.","english":"She talks as if she never doubted herself."}},{"question":{"spanish":"\xbfQu\xe9 har\xedas si no tuvieras miedo al fracaso?","english":"What would you do if you were not afraid of failure?"},"answer":{"spanish":"Si no tuviera miedo al fracaso, lanzar\xeda mi propio negocio.","english":"If I were not afraid of failure, I would launch my own business."}},{"question":{"spanish":"\xbfQu\xe9 te gustar\xeda que cambiara este a\xf1o?","english":"What would you like to be different this year?"},"answer":{"spanish":"Ojal\xe1 pudiera pasar m\xe1s tiempo con mi familia.","english":"I wish I could spend more time with my family."}}]}}}')}}]);